static void lzma_encode_literal(LZMAState* lzma_state, EncoderInterface* enc) {
  LZMAPacketHeader head = {.match = 0};
  lzma_encode_packet_header(lzma_state, enc, &head);

  LZMAProbabilityModel* probs = &lzma_state->probs;
