pub struct MaxHeap {
    capacity: usize,
    data: Vec<u32>,
    comparator: Box<dyn Fn(u32, u32) -> i32>,
}

impl MaxHeap {
    pub fn new(capacity: usize, comparator: Box<dyn Fn(u32, u32) -> i32>) -> Self {
        MaxHeap {
            capacity,
            data: Vec::with_capacity(capacity),
            comparator,
        }
    }

    fn heapify_up(&mut self, mut idx: usize) {
        while idx > 0 {
            let parent = (idx - 1) / 2;
            let cmp = (self.comparator)(self.data[parent], self.data[idx]);
            if cmp >= 0 {
                break;
            }
            self.data.swap(parent, idx);
            idx = parent;
        }
    }

    fn heapify_down(&mut self, mut idx: usize) {
        loop {
            let left = 2 * idx + 1;
            let right = left + 1;
            let mut largest = idx;

            if left < self.data.len() && (self.comparator)(self.data[left], self.data[largest]) > 0 {
                largest = left;
            }
            if right < self.data.len() && (self.comparator)(self.data[right], self.data[largest]) > 0 {
                largest = right;
            }

            if largest == idx {
                break;
            }

            self.data.swap(idx, largest);
            idx = largest;
        }
    }

    pub fn insert(&mut self, value: u32) -> bool {
        if self.data.len() == self.capacity {
            return false;
        }
        self.data.push(value);
        let idx = self.data.len() - 1;
        self.heapify_up(idx);
        true
    }

